"use strict";parserFactory.registerDeadSite("mvlempyr.com",()=>new MvlempyrParser),parserFactory.register("mvlempyr.io",()=>new MvlempyrParser);class MvlempyrParser extends Parser{constructor(){super(),this.minimumThrottle=1e3}async getChapterUrls(e){let t=e.querySelector("div.novel-image-wrapper img").src.split("/").pop().split(".")[0],r=parseInt(e.querySelector("div#chapter-count").textContent)?parseInt(e.querySelector("div#chapter-count").textContent):-1,l=[...e.querySelectorAll("a.chapter-item h3")].map(e=>e.textContent.replace(/^\d+\.\s*/,""));if(-1==r){let t=new RegExp("numberOfChapters.*?,"),l=new RegExp("[0-9]+"),n=[...e.scripts].map(e=>e.outerHTML);r=parseInt(n.filter(e=>e.match(t))?.[0].match(t)?.[0].match(l)?.[0])}let n=[];for(let e=1;e<=r;e++){let r=`https://www.mvlempyr.io/chapter/${t}-${e}`;null==l[e-1]?n.push({sourceUrl:r,title:"[placeholder]"}):n.push({sourceUrl:r,title:l[e-1]})}return n}findContent(e){return e.querySelector("div#chapter")||e.querySelector("#chapter-content")}extractTitleImpl(e){return e.querySelector("h1.novel-title")}extractAuthor(e){let t=e.querySelector("div.mobileauthorname");return t?.textContent??super.extractAuthor(e)}findChapterTitle(e){return e.querySelector("#span-28-1305853").textContent}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.novel-image-wrapper")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.synopsis")].map(e=>e.innerHTML.replace(/<br><br>/g,"\n\n").replace(/<br>/g,"\n"))}extractSubject(e){let t=[...e.querySelectorAll("div.genere-tagslist a")],r=new RegExp("^#");return t.map(e=>e.textContent.trim().replace(r,"")).join(", ")}}